// Re-assert the per-page forall ensures with their *own* triggers so that
// when z3 needs to discharge the determinism obligation it has both
// quantifiers individually instantiable.  Verus must prove each of these
// — they follow directly from the corresponding ensures clause.
assert(forall|p: PagePtr|
    #![trigger post1_self_.page_is_mapped(p)]
    #![trigger post1_self_.page_mappings(p)]
    post1_self_.page_is_mapped(p) && p != target_ptr ==>
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));
assert(forall|p: PagePtr|
    #![trigger post2_self_.page_is_mapped(p)]
    #![trigger post2_self_.page_mappings(p)]
    post2_self_.page_is_mapped(p) && p != target_ptr ==>
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p));

// Bridge the target_ptr case directly: both post1/post2 mappings at
// target_ptr equal pre.page_mappings(target_ptr).insert((pcid, va)),
// and both io_mappings equal pre.page_io_mappings(target_ptr).
assert(post1_self_.page_mappings(target_ptr) =~= post2_self_.page_mappings(target_ptr));
assert(post1_self_.page_io_mappings(target_ptr) =~= post2_self_.page_io_mappings(target_ptr));

// Bridge the visible spec-method state across the two runs via pre_self_.
// Each conjunct chains two `=~=` ensures into a single post1 ~ post2 fact.
assert(post1_self_.free_pages_4k()       =~= post2_self_.free_pages_4k());
assert(post1_self_.free_pages_2m()       =~= post2_self_.free_pages_2m());
assert(post1_self_.free_pages_1g()       =~= post2_self_.free_pages_1g());
assert(post1_self_.allocated_pages_4k()  =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m()  =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g()  =~= post2_self_.allocated_pages_1g());
assert(post1_self_.mapped_pages_4k()     =~= post2_self_.mapped_pages_4k());
assert(post1_self_.mapped_pages_2m()     =~= post2_self_.mapped_pages_2m());
assert(post1_self_.mapped_pages_1g()     =~= post2_self_.mapped_pages_1g());
assert(post1_self_.container_map_4k@.dom() =~= post2_self_.container_map_4k@.dom());
assert(post1_self_.container_map_2m@.dom() =~= post2_self_.container_map_2m@.dom());
assert(post1_self_.container_map_1g@.dom() =~= post2_self_.container_map_1g@.dom());

// Bridge the per-page page_is_mapped equivalence by going through pre_self_.
assert(forall|p: PagePtr| #![auto]
    post1_self_.page_is_mapped(p) <==> post2_self_.page_is_mapped(p));

// Length agreement on the free_pages_4k linked list field (a direct
// numeric ensures, replayed to make sure z3 sees it for both runs).
assert(post1_self_.free_pages_4k.len() == post2_self_.free_pages_4k.len());

// Pointwise on the non-target case: pull both per-page foralls together
// into a single bi-implication of post1.page_mappings(p) == post2.page_mappings(p)
// (and likewise for io_mappings).  This is the actual trigger-bridge:
// instantiate each forall on the same `p` so their RHS unify via pre_self_.
assert forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != target_ptr implies
        post1_self_.page_mappings(p)    =~= post2_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= post2_self_.page_io_mappings(p) by {
    // post1.page_is_mapped(p) ==> pre.page_is_mapped(p) (ensures)
    //                         ==> post2.page_is_mapped(p) (ensures).
    // With p != target_ptr, both forall instances fire and force the RHS
    // through pre_self_.
    assert(pre_self_.page_is_mapped(p));
    assert(post2_self_.page_is_mapped(p));
}
